var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네가 바라는 건 마왕 타기리온의 죽음.","JPN":"アナタが望むのは魔王タギリオンの死。","ENG":"What you wish for is Thagirion's death.","TWN":"你所許願的是魔王塔基里翁的死亡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"녀석이 지금까지 손에 넣은 황금가지는 적어도 여섯.","JPN":"あいつが今まで手に入れた黄金の枝は少なくとも6本。","ENG":"Yet, she has at least six Golden Branches in her possession.","TWN":"她至今為止得到至少六根金枝。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"마왕의 심장을 노리려면 일곱 번을 꿰뚫어야만 해.","JPN":"魔王の心臓を7回は射抜く必要があるわ。","ENG":"If you are to aim for the Demon Lord's heart, you will have to strike it seven times.","TWN":"要想貫穿魔王的心臟，就必須命中七發。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그러니 너에게 가장 필요한 건… 그 어떤 수단도 무시하고 심장을 꿰뚫는 필중의 탄환이겠지.","JPN":"だから今のアナタに必要なのは……どんな状況でも必ず心臓を貫く弾丸よ。","ENG":"So, what you will need is... a bullet that guarantees to penetrate her heart in any condition.","TWN":"所以你最需要的是…無論用什麼手段都能刺穿心臟的必中子彈。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"또…? 맞았다고?","JPN":"また……？　当たった？","ENG":"I got hit... again?","TWN":"又…？打中我了？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이걸로, 세 번째.","JPN":"これで、3発目。","ENG":"That will be the third time.","TWN":"這是，第三發。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"분명 피했을 텐데, 어째서…?","JPN":"たしかに避けたはずなのに、どうして……？","ENG":"I am certain I dodged it. But why...?","TWN":"明明躲開了，怎麼會…？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"어째서 피하지 못하는 거지?!","JPN":"どうして避けられないの！？","ENG":"Why am I not able to avoid it?!","TWN":"為什麼躲不開？！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"네 영혼을 대가로 견뎌낼 수 있는 건 여섯 발이 한계일 거야.","JPN":"アナタの魂を代価に耐えられるのは6発が限界よ。","ENG":"The most your soul can endure is likely six shots.","TWN":"用你的靈魂作為代價，最多只能承受六發子彈。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"다행인 점은, 우린 이미 녀석의 심장을 한 차례 꿰뚫는데 성공했다는 거지.","JPN":"幸いなことに、アタシたちはすでにあいつの心臓を一度、撃ち抜くことに成功したわ。","ENG":"Luckily, we have already succeeded in striking her heart once.","TWN":"幸運的是，我們已經成功刺穿她的心臟一次。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"너에게 주어진 여섯 발이, 전부 타기리온의 심장으로 향하게 할 수만 있다면…","JPN":"アナタに与えられた6発が全て、タギリオンの心臓に当たれば……","ENG":"If you are able to shoot all six bullets directly aimed at Thagirion's heart...","TWN":"如果你能讓所有六發子彈都射中…"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"녀석을 충분히 꺾을 수 있어.","JPN":"十分にやつを倒せる。","ENG":"then you will definitely defeat her.","TWN":"就能徹底擊敗她。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네 번째…!","JPN":"4発目……！","ENG":"Fourth...!","TWN":"第四發…！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"탄환따위가… 내 방어까지 꿰뚫었다고?","JPN":"弾丸が……私の防御を貫通した？","ENG":"A mere bullet... penetrated my defense?","TWN":"子彈…竟然穿透了我的防禦？"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"큭…","JPN":"グッ……","ENG":"Kgh...","TWN":"咳…"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"막을 수 없다면…!","JPN":"止められないなら……！","ENG":"If I cannot block them...!","TWN":"如果擋不住的話…！"},"stage":{"bg":"SKY_RED","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"하지만 명심해.","JPN":"でも、肝に銘じておいて。","ENG":"Keep in mind.","TWN":"但是要記住。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"황금가지를 품은 마왕과 달리, 네 목숨은 하나뿐이라는 걸.","JPN":"黄金の枝を持つ魔王と違って、アナタの命は一つだけだということを。","ENG":"Unlike the Demon Lord with her Golden Branches, you only have one life.","TWN":"和擁有金枝的魔王不同，你只有一條命。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};